  "inlineSchema": "// This is your Prisma schema file\n// Learn more: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"debian-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ── Enums ────────────────────────────────────────────────────────────\n\nenum Role {\n  admin\n  supervisor\n  agent\n}\n\nenum UserStatus {\n  active\n  inactive\n  on_break\n  offline\n}\n\nenum CampaignType {\n  standard\n  vip\n}\n\nenum CampaignStatus {\n  active\n  paused\n  closed\n}\n\nenum Priority {\n  normal\n  high\n}\n\nenum LeadStatus {\n  uncontacted\n  contacted\n  lead\n  not_interested\n  dnd\n  invalid\n  callback\n}\n\nenum FollowUpStatus {\n  pending\n  done\n  missed\n  rescheduled\n}\n\n// ── Models ───────────────────────────────────────────────────────────\n\nmodel Team {\n  id           String   @id @default(uuid())\n  name         String\n  supervisor   User?    @relation(\"TeamSupervisor\", fields: [supervisorId], references: [id])\n  supervisorId String?\n  createdAt    DateTime @default(now())\n\n  members   User[]     @relation(\"TeamMembers\")\n  campaigns Campaign[]\n\n  @@map(\"teams\")\n}\n\nmodel User {\n  id             String     @id @default(uuid())\n  name           String\n  email          String     @unique\n  passwordHash   String\n  role           Role\n  team           Team?      @relation(\"TeamMembers\", fields: [teamId], references: [id])\n  teamId         String?\n  status         UserStatus @default(offline)\n  breakStartedAt DateTime?\n  createdAt      DateTime   @default(now())\n  updatedAt      DateTime   @updatedAt\n\n  // Supervisor back-ref\n  supervisorOfTeam Team[] @relation(\"TeamSupervisor\")\n\n  // Relations\n  createdCampaigns Campaign[]       @relation(\"CampaignCreator\")\n  campaignAccess   CampaignAgent[]\n  assignedLeads    Lead[]           @relation(\"LeadAssignee\")\n  callLogs         CallLog[]\n  followUps        FollowUp[]\n  createdTags      DispositionTag[]\n  breakLogs        BreakLog[]\n  comments         LeadComment[]\n\n  @@map(\"users\")\n}\n\nmodel Campaign {\n  id          String         @id @default(uuid())\n  name        String\n  description String?\n  type        CampaignType   @default(standard)\n  status      CampaignStatus @default(active)\n  priority    Priority       @default(normal)\n  script      String? // Rich-text HTML for call script (Phase 3)\n  createdBy   User           @relation(\"CampaignCreator\", fields: [createdById], references: [id])\n  createdById String\n  team        Team?          @relation(fields: [teamId], references: [id])\n  teamId      String?\n  createdAt   DateTime       @default(now())\n  closedAt    DateTime?\n\n  // Relations\n  agents CampaignAgent[]\n  leads  Lead[]\n\n  @@map(\"campaigns\")\n}\n\n/// Junction table — controls which agents can access a campaign.\n/// For VIP campaigns this is a whitelist; for standard campaigns\n/// all assigned agents are inserted here on assignment.\nmodel CampaignAgent {\n  campaign   Campaign @relation(fields: [campaignId], references: [id])\n  campaignId String\n  agent      User     @relation(fields: [agentId], references: [id])\n  agentId    String\n\n  @@id([campaignId, agentId])\n  @@map(\"campaign_agents\")\n}\n\nmodel Lead {\n  id           String     @id @default(uuid())\n  campaign     Campaign   @relation(fields: [campaignId], references: [id])\n  campaignId   String\n  phone        String     @unique // Stored plain; masking happens at API layer\n  email        String?\n  name         String?\n  customFields Json? // Extra CSV columns stored as JSONB\n  assignedTo   User?      @relation(\"LeadAssignee\", fields: [assignedToId], references: [id])\n  assignedToId String? // NULL = unassigned pool\n  status       LeadStatus @default(uncontacted)\n  priority     Priority   @default(normal)\n  isDnd        Boolean    @default(false)\n  createdAt    DateTime   @default(now())\n  lastCalledAt DateTime?\n\n  // Relations\n  callLogs  CallLog[]\n  followUps FollowUp[]\n  comments  LeadComment[]\n\n  // Indexes\n  @@index([assignedToId])\n  @@index([campaignId, status])\n  @@index([campaignId, assignedToId])\n  @@map(\"leads\")\n}\n\nmodel LeadComment {\n  id        String   @id @default(uuid())\n  lead      Lead     @relation(fields: [leadId], references: [id])\n  leadId    String\n  agent     User     @relation(fields: [agentId], references: [id])\n  agentId   String\n  content   String\n  createdAt DateTime @default(now())\n\n  @@index([leadId])\n  @@map(\"lead_comments\")\n}\n\nmodel CallLog {\n  id              String   @id @default(uuid())\n  lead            Lead     @relation(fields: [leadId], references: [id])\n  leadId          String\n  agent           User     @relation(fields: [agentId], references: [id])\n  agentId         String\n  dispositionTag  String\n  durationSeconds Int      @default(0)\n  notes           String?\n  telephonyRef    String? // Provider call ID — populated after telephony integration\n  calledAt        DateTime @default(now())\n\n  @@index([agentId, calledAt])\n  @@index([leadId])\n  @@map(\"call_logs\")\n}\n\nmodel FollowUp {\n  id          String         @id @default(uuid())\n  lead        Lead           @relation(fields: [leadId], references: [id])\n  leadId      String\n  agent       User           @relation(fields: [agentId], references: [id])\n  agentId     String\n  scheduledAt DateTime\n  status      FollowUpStatus @default(pending)\n  notes       String?\n  createdAt   DateTime       @default(now())\n  completedAt DateTime?\n\n  @@index([agentId, scheduledAt])\n  @@index([scheduledAt, status])\n  @@map(\"follow_ups\")\n}\n\nmodel DispositionTag {\n  id          String   @id @default(uuid())\n  name        String   @unique\n  colour      String   @default(\"#6366f1\")\n  isSystem    Boolean  @default(false)\n  createdBy   User?    @relation(fields: [createdById], references: [id])\n  createdById String?\n  createdAt   DateTime @default(now())\n\n  @@map(\"disposition_tags\")\n}\n\nmodel BreakLog {\n  id        String    @id @default(uuid())\n  agent     User      @relation(fields: [agentId], references: [id])\n  agentId   String\n  startedAt DateTime  @default(now())\n  endedAt   DateTime?\n\n  @@index([agentId, startedAt])\n  @@map(\"break_logs\")\n}\n\nmodel DndBlocklist {\n  id      String   @id @default(uuid())\n  phone   String   @unique\n  reason  String?\n  addedAt DateTime @default(now())\n\n  @@map(\"dnd_blocklist\")\n}\n",
